const fields = ($json.field_data || []).reduce((acc, f) => { acc[f.name] = (f.values || [])[0]; return acc; }, {});
return [{ json: {
  source: 'facebook_ads',
  event_code: 'lead.created',
  payload: {
    customer: { name: fields.full_name || fields.name, phone: fields.phone_number, email: fields.email },
    interest: fields.interest || fields.product || 'consulta_geral',
    utm: { source: 'facebook', medium: 'paid', campaign: $json.campaign_name, form: $json.form_name },
    fb_lead_id: $json.id
  }
} }];
